module top_module(clk, reset, d, q, qn);input clk;
input reset;
input d;
output q;
output qn;

reg q;
reg qn;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge reset or posedge dbg_halt) begin
    if (reset) begin
        q <= 1'b0;
        qn <= 1'b1;
    end else begin
        q <= d;
        qn <= ~d;
    end
end

endmodule
